import{_ as r,o,c as l,ag as e}from"./chunks/framework.BbyMWZAR.js";const h=JSON.parse('{"title":"HTTP 版本演进：1.0 / 1.1 / 2 / 3 各自解决了什么问题？","description":"","frontmatter":{"title":"HTTP 版本演进：1.0 / 1.1 / 2 / 3 各自解决了什么问题？","difficulty":"hard","tags":["HTTP","HTTP/2","HTTP/3","QUIC","队头阻塞"],"estimate":30},"headers":[],"relativePath":"domains/browser/qa/qa-09-http-versions.md","filePath":"domains/browser/qa/qa-09-http-versions.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-09-http-versions.md"};function n(a,t,s,T,d,P){return o(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="问答-09-高级-http-版本演进-1-0-1-1-2-3-各自解决了什么问题" tabindex="-1">问答 09（高级）：HTTP 版本演进：1.0 / 1.1 / 2 / 3 各自解决了什么问题？ <a class="header-anchor" href="#问答-09-高级-http-版本演进-1-0-1-1-2-3-各自解决了什么问题" aria-label="Permalink to &quot;问答 09（高级）：HTTP 版本演进：1.0 / 1.1 / 2 / 3 各自解决了什么问题？&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>HTTP/1.0、HTTP/1.1、HTTP/2、HTTP/3 之间的关键差异是什么？分别解决了前代的什么痛点？请覆盖连接复用、多路复用、头部压缩、队头阻塞、传输层协议等。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>HTTP/1.0</strong></p><ul><li>每个请求一个 TCP 连接，用完就断。</li><li>头部无压缩、无 Host 头（一个 IP 只能挂一个站）。</li><li>没有持久连接（默认），需要 <code>Connection: keep-alive</code> 显式开启，但支持度参差。</li></ul><p><strong>HTTP/1.1（1997）</strong> 新增 / 改进：</p><ul><li><strong>Host 头</strong>：一个 IP 支持多站点（virtual host）。</li><li><strong>默认持久连接</strong>：Keep-Alive 一条 TCP 复用多次请求。</li><li><strong>管线化（Pipelining）</strong>：允许在同一连接上连发多个请求（但响应必须按序返回），实际浏览器几乎都关闭，因为<strong>队头阻塞（HOL）</strong> 严重。</li><li><strong>分块传输编码</strong>：<code>Transfer-Encoding: chunked</code>，服务端可流式响应。</li><li><strong>缓存机制升级</strong>：<code>Cache-Control</code>、<code>ETag</code>、<code>If-None-Match</code>。</li><li><strong>范围请求</strong>：<code>Range: bytes=</code> 支持断点续传、视频拖动。</li><li><strong>100 Continue</strong>：客户端可先探测服务器是否愿意接收 body。</li></ul><p><strong>痛点残留</strong></p><ul><li>每个请求仍要「一发一收」串行，多域名分片（domain sharding）只是 workaround。</li><li>头部冗长，重复发送 Cookie / User-Agent 等大量重复字段。</li><li>TCP 队头阻塞：单条连接下前面响应没到，后面就得等。</li></ul><p><strong>HTTP/2（2015，SPDY 演化而来）</strong> 关键改进：</p><ul><li><strong>二进制分帧</strong>：不是文本协议，请求 / 响应拆成帧（HEADERS / DATA / SETTINGS 等），在一条 TCP 上多路复用（Stream）。</li><li><strong>多路复用</strong>：一条 TCP 连接上并行发送多个请求 / 响应，解决 HTTP 层队头阻塞。</li><li><strong>HPACK 头部压缩</strong>：静态表 + 动态表 + Huffman 编码，重复头几乎零成本。</li><li><strong>Server Push</strong>（已在 Chrome 106 移除）：服务端可主动推送资源，实践中命中率低被弃用。</li><li><strong>流优先级</strong>：告诉服务端哪些请求更重要。</li><li>强制 TLS：主流实现只在 HTTPS 下工作。</li></ul><p><strong>残留痛点</strong></p><ul><li><strong>TCP 层队头阻塞仍存在</strong>：一条 TCP 连接里丢一个包，后面所有 stream 都要等重传。</li><li>TCP + TLS 握手仍要多个 RTT。</li><li>移动网络切换 IP 会中断连接。</li></ul><p><strong>HTTP/3（2022 正式，RFC 9114）</strong> 关键改进：</p><ul><li><strong>基于 QUIC（UDP）</strong>：把可靠传输 + 加密 + 多路复用做进用户态协议。</li><li><strong>彻底解决队头阻塞</strong>：每个 stream 有独立的可靠传输，丢包只影响自己那条流。</li><li><strong>1-RTT / 0-RTT 建连</strong>：把 TCP 握手 + TLS 1.3 合并；后续连接可 0-RTT 直接发数据（有重放风险，仅限幂等请求）。</li><li><strong>连接迁移</strong>：连接由 Connection ID 而非四元组标识，手机切 WiFi / 4G 也不断。</li><li><strong>QPACK 头部压缩</strong>：类似 HPACK 但避免了 HPACK 在乱序场景下的问题。</li><li>依赖协商：先走 HTTP/2，服务端返回 <code>Alt-Svc: h3=&quot;:443&quot;</code> 告诉客户端支持 HTTP/3，之后升级。</li></ul><p><strong>对比表</strong></p><table tabindex="0"><thead><tr><th>特性</th><th>HTTP/1.1</th><th>HTTP/2</th><th>HTTP/3</th></tr></thead><tbody><tr><td>传输层</td><td>TCP</td><td>TCP</td><td>UDP + QUIC</td></tr><tr><td>报文格式</td><td>文本</td><td>二进制帧</td><td>二进制帧</td></tr><tr><td>并发</td><td>一连接一请求（Pipelining 失败）</td><td>多路复用（一 TCP）</td><td>多路复用（一 QUIC 连接，无 HOL）</td></tr><tr><td>头压缩</td><td>无</td><td>HPACK</td><td>QPACK</td></tr><tr><td>握手</td><td>TCP + TLS 分开</td><td>TCP + TLS 分开</td><td>QUIC 内置 TLS 1.3</td></tr><tr><td>加密</td><td>可选</td><td>事实强制</td><td>强制</td></tr></tbody></table><h2 id="追问-1-http-2-已经多路复用了-为什么还有「队头阻塞」问题" tabindex="-1">追问 1：HTTP/2 已经多路复用了，为什么还有「队头阻塞」问题？ <a class="header-anchor" href="#追问-1-http-2-已经多路复用了-为什么还有「队头阻塞」问题" aria-label="Permalink to &quot;追问 1：HTTP/2 已经多路复用了，为什么还有「队头阻塞」问题？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>HTTP/2 的多路复用发生在<strong>应用层</strong>：多个 Stream 的帧在一条 TCP 连接里交织。</li><li>但 TCP 保证字节流有序，一旦某个 TCP 段丢了，需要重传，<strong>内核 TCP 层不会把后面的数据交给应用</strong>（要按序）。</li><li>结果：应用层不同 stream 的帧其实已经到了，却被 TCP 卡住不能上交。丢包率高的网络（移动、跨国）尤其明显。</li><li>HTTP/3 用 QUIC 在用户态实现独立 stream 的可靠传输，一条 stream 丢包只影响自己那条，别的可以照常上交，彻底解决。</li></ul><h2 id="追问-2-hpack-是怎么压缩头部的-为什么能压这么多" tabindex="-1">追问 2：HPACK 是怎么压缩头部的？为什么能压这么多？ <a class="header-anchor" href="#追问-2-hpack-是怎么压缩头部的-为什么能压这么多" aria-label="Permalink to &quot;追问 2：HPACK 是怎么压缩头部的？为什么能压这么多？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>三招： <ol><li><strong>静态表</strong>：预定义 61 个常用头（<code>:method GET</code>、<code>:status 200</code>、<code>accept-encoding gzip, deflate</code> 等），发送时只发索引（1 字节）。</li><li><strong>动态表</strong>：连接内首次出现的自定义头（如 Cookie、Authorization）被加入动态表，后续复用只发索引。</li><li><strong>Huffman 编码</strong>：字符串用可变长编码，进一步压缩。</li></ol></li><li>效果：一次请求头可能从 1KB 压到几十字节，长连接下累计节省显著。</li><li>代价：客户端和服务端各自维护动态表，需要一定内存；安全需谨慎，HPACK 的一些实现历史上被 CRIME 类攻击关注过（HTTPS/HTTP2 的压缩侧信道），实践中通过分块 + 敏感头不放动态表来缓解。</li></ul><h2 id="追问-3-什么时候客户端会用-http-3-为什么第一次访问一般还是-http-2" tabindex="-1">追问 3：什么时候客户端会用 HTTP/3？为什么第一次访问一般还是 HTTP/2？ <a class="header-anchor" href="#追问-3-什么时候客户端会用-http-3-为什么第一次访问一般还是-http-2" aria-label="Permalink to &quot;追问 3：什么时候客户端会用 HTTP/3？为什么第一次访问一般还是 HTTP/2？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>现代浏览器不会主动尝试 HTTP/3（UDP 可能被防火墙 block），第一次先按老流程走 TCP + TLS + HTTP/2 或 1.1。</li><li>服务端在响应头里返回 <code>Alt-Svc: h3=&quot;:443&quot;; ma=86400</code>，告诉客户端「我支持 HTTP/3，端口和有效期」。</li><li>浏览器把这个信息缓存起来，<strong>下次访问同域名直接尝试 HTTP/3</strong>。如果连不上（比如网络屏蔽 UDP），自动降级回 HTTP/2。</li><li>有些客户端支持 <code>HTTPS</code> DNS record（Type 65）预先拿到 ALPN 信息，第一次就能直接上 H3。</li><li>生产上要注意：UDP 有时被限速或被视为 P2P 流量丢弃，需要监控 H3 命中率。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc9113.html" target="_blank" rel="noreferrer">RFC 9113: HTTP/2</a>：HTTP/2 多路复用与帧协议</li><li><a href="https://www.rfc-editor.org/rfc/rfc9114.html" target="_blank" rel="noreferrer">RFC 9114: HTTP/3</a>：HTTP/3 基于 QUIC 的语义映射</li><li><a href="https://hpbn.co/http2/" target="_blank" rel="noreferrer">hpbn.co: HTTP/2</a>：HTTP 版本演进与队头阻塞分析</li></ul>',30)])])}const c=r(i,[["render",n]]);export{h as __pageData,c as default};
